#include <stdio.h>
#include <string.h>
#include <stdlib.h>

const char *MORSE[36] = {
    ".-","-...","-.-.","-..",".","..-.","--.","....","..",".---",
    "-.-",".-..","--","-.","---",".--.","--.-",".-.","...","-",
    "..-","...-",".--","-..-","-.--","--..",
    "-----",".----","..---","...--","....-",".....","-....","--...","---..","----."
};

int idx(char c){
    if(c>='A' && c<='Z') return c-'A';
    return 26 + (c-'0');
}

int main(){
    int T; char line[256];
    if(scanf("%d", &T)!=1) return 0;
    getchar(); // consume newline after T
    while(T--){
        if(!fgets(line, sizeof(line), stdin)) break;
        size_t len = strlen(line);
        if(len && line[len-1]=='\n') line[len-1]='\0';
        char *word = strtok(line, " ");
        int firstWord = 1;
        while(word){
            if(!firstWord) printf(" / ");
            firstWord = 0;
            for(size_t i=0;i<strlen(word);++i){
                if(i) printf(" ");
                printf("%s", MORSE[idx(word[i])]);
            }
            word = strtok(NULL, " ");
        }
        if(T) printf("\n");
    }
    return 0;
}

